// IntegrityValidator.java - HMAC-based integrity validation
package com.b2b.orderservice;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.math.BigDecimal;
import java.nio.charset.StandardCharsets;
import java.security.InvalidKeyException;
import java.security.NoSuchAlgorithmException;
import java.util.Base64;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class IntegrityValidator {

    private static final String HMAC_ALGORITHM = "HmacSHA256";
    private static final IntegrityValidator INSTANCE = new IntegrityValidator();

    // In production, load from secure key store per customer
    private final Map<String, String> customerSecrets = new ConcurrentHashMap<>();

    private IntegrityValidator() {
        customerSecrets.put("CUST-001", "s3cr3tK3y_CUST001_v2");
        customerSecrets.put("CUST-002", "s3cr3tK3y_CUST002_v2");
        customerSecrets.put("CUST-003", "s3cr3tK3y_CUST003_v2");
    }

    public static IntegrityValidator getInstance() { return INSTANCE; }

    public boolean validateRequestIntegrity(OrderRequest request) {
        if (request.getRequestHash() == null || request.getRequestHash().isEmpty()) {
            return false;
        }

        String secret = customerSecrets.get(request.getCustomerId());
        if (secret == null) {
            return false;
        }

        String computedHash = computeHash(request, secret);
        return computedHash != null && constantTimeEquals(computedHash, request.getRequestHash());
    }

    public String computeHash(OrderRequest request, String secret) {
        try {
            StringBuilder payload = new StringBuilder();
            payload.append(request.getCustomerId()).append("|");
            payload.append(request.getCustomerName()).append("|");
            payload.append(request.getShippingAddress()).append("|");

            if (request.getItems() != null) {
                for (OrderItem item : request.getItems()) {
                    payload.append(item.getItemId()).append(":");
                    payload.append(item.getQuantity()).append(":");
                    payload.append(item.getUnitPrice().toPlainString()).append(";");
                }
            }

            Mac mac = Mac.getInstance(HMAC_ALGORITHM);
            SecretKeySpec keySpec = new SecretKeySpec(secret.getBytes(StandardCharsets.UTF_8), HMAC_ALGORITHM);
            mac.init(keySpec);
            byte[] hashBytes = mac.doFinal(payload.toString().getBytes(StandardCharsets.UTF_8));
            return Base64.getEncoder().encodeToString(hashBytes);
        } catch (NoSuchAlgorithmException | InvalidKeyException e) {
            return null;
        }
    }

    // Constant-time comparison to prevent timing attacks
    private boolean constantTimeEquals(String a, String b) {
        if (a.length() != b.length()) {
            return false;
        }
        int result = 0;
        for (int i = 0; i < a.length(); i++) {
            result |= a.charAt(i) ^ b.charAt(i);
        }
        return result == 0;
    }

    public String getCustomerSecret(String customerId) {
        return customerSecrets.get(customerId);
    }
}

// InputSanitizer.java - Input validation and sanitization
package com.b2b.orderservice;

import java.math.BigDecimal;
import java.util.regex.Pattern;

public class InputSanitizer {

    private static final Pattern ALPHANUMERIC_DASH = Pattern.compile("^[a-zA-Z0-9\\-]+$");
    private static final Pattern SAFE_TEXT = Pattern.compile("^[a-zA-Z0-9\\s\\-.,#/]+$");
    private static final int MAX_STRING_LENGTH = 500;
    private static final int MAX_ITEMS_PER_ORDER = 100;
    private static final BigDecimal MAX_ORDER_TOTAL = new BigDecimal("1000000.00");
    private static final BigDecimal MIN_PRICE = new BigDecimal("0.01");
    private static final BigDecimal MAX_PRICE = new BigDecimal("999999.99");

    public static String sanitizeId(String input) {
        if (input == null || input.trim().isEmpty()) {
            return null;
        }
        String trimmed = input.trim();
        if (trimmed.length() > 50) {
            return null;
        }
        if (!ALPHANUMERIC_DASH.matcher(trimmed).matches()) {
            return null;
        }
        return trimmed;
    }

    public static String sanitizeText(String input) {
        if (input == null || input.trim().isEmpty()) {
            return null;
        }
        String trimmed = input.trim();
        if (trimmed.length() > MAX_STRING_LENGTH) {
            return null;
        }
        // Remove any XML/SOAP injection characters
        trimmed = trimmed.replaceAll("[<>&\"']", "");
        if (!SAFE_TEXT.matcher(trimmed).matches()) {
            return null;
        }
        return trimmed;
    }

    public static boolean isValidQuantity(int quantity) {
        return quantity > 0 && quantity <= 10000;
    }

    public static boolean isValidPrice(BigDecimal price) {
        return price != null && price.compareTo(MIN_PRICE) >= 0 && price.compareTo(MAX_PRICE) <= 0;
    }

    public static boolean isValidItemCount(int count) {
        return count > 0 && count <= MAX_ITEMS_PER_ORDER;
    }

    public static boolean isValidOrderTotal(BigDecimal total) {
        return total != null && total.compareTo(BigDecimal.ZERO) > 0 && total.compareTo(MAX_ORDER_TOTAL) <= 0;
    }
}

// SOAPSecurityHandler.java - SOAP message handler for security
package com.b2b.orderservice;

import javax.xml.namespace.QName;
import javax.xml.soap.SOAPBody;
import javax.xml.soap.SOAPEnvelope;
import javax.xml.soap.SOAPException;
import javax.xml.soap.SOAPMessage;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import java.io.ByteArrayOutputStream;
import java.util.Collections;
import java.util.Set;
import java.util.logging.Level;
import java.util.logging.Logger;

public class SOAPSecurityHandler implements SOAPHandler<SOAPMessageContext> {

    private static final Logger LOGGER = Logger.getLogger(SOAPSecurityHandler.class.getName());
    private static final int MAX_MESSAGE_SIZE = 1024 * 1024; // 1MB max
    private static final int MAX_XML_DEPTH = 10;

    @Override
    public Set<QName> getHeaders() {
        return Collections.emptySet();
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean isOutbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (!isOutbound) {
            try {
                SOAPMessage message = context.getMessage();

                // Check message size to prevent DoS
                if (!validateMessageSize(message)) {
                    LOGGER.warning("SOAP message exceeds maximum allowed size");
                    throw new RuntimeException("Message size exceeds limit");
                }

                // Validate SOAP structure
                SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
                SOAPBody body = envelope.getBody();

                if (body == null) {
                    LOGGER.warning("SOAP body is null - potential tampering");
                    throw new RuntimeException("Invalid SOAP message structure");
                }

                // Check for SOAP injection patterns
                if (!validateNoInjection(message)) {
                    LOGGER.warning("Potential SOAP injection detected");
                    throw new RuntimeException("Invalid SOAP message content");
                }

                LOGGER.info("SOAP security validation passed");

            } catch (SOAPException e) {
                LOGGER.log(Level.SEVERE, "SOAP security handler error", e);
                throw new RuntimeException("SOAP message validation failed", e);
            }
        }

        return true;
    }

    private boolean validateMessageSize(SOAPMessage message) {
        try {
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            message.writeTo(baos);
            int size = baos.size();
            return size <= MAX_MESSAGE_SIZE;
        } catch (Exception e) {
            return false;
        }
    }

    private boolean validateNoInjection(SOAPMessage message) {
        try {
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            message.writeTo(baos);
            String content = baos.toString("UTF-8");

            // Check for XXE patterns
            if (content.contains("<!DOCTYPE") || content.contains("<!ENTITY") ||
                content.contains("SYSTEM") || content.contains("file://") ||
                content.contains("expect://") || content.contains("php://")) {
                LOGGER.warning("XXE injection pattern detected");
                return false;
            }

            // Check for XPath injection patterns
            if (content.contains("' or '") || content.contains("\" or \"") ||
                content.contains("1=1") || content.contains("--")) {
                LOGGER.warning("Potential injection pattern detected");
                return false;
            }

            return true;
        } catch (Exception e) {
            return false;
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        LOGGER.warning("SOAP fault occurred");
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // cleanup
    }
}

// OrderServiceImpl.java - Service Implementation
package com.b2b.orderservice;

import javax.jws.HandlerChain;
import javax.jws.WebService;
import javax.xml.ws.BindingType;
import javax.xml.ws.soap.SOAPBinding;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService(
    endpointInterface = "com.b2b.orderservice.OrderService",
    serviceName = "OrderService",
    portName = "OrderServicePort",
    targetNamespace = "http://b2b.com/orderservice"
)
@BindingType(SOAPBinding.SOAP12HTTP_BINDING)
@HandlerChain(file = "handler-chain.xml")
public class OrderServiceImpl implements OrderService {

    private static final Logger LOGGER = Logger.getLogger(OrderServiceImpl.class.getName());
    private final ProductCatalog productCatalog = ProductCatalog.getInstance();
    private final IntegrityValidator integrityValidator = IntegrityValidator.getInstance();
    private final Map<String, OrderRecord> orderStore = new ConcurrentHashMap<>();

    // Simple order record for tracking
    private static class OrderRecord {
        String orderId;
        String customerId;
        String status;
        BigDecimal totalPrice;
        long timestamp;

        OrderRecord(String orderId, String customerId, String status, BigDecimal totalPrice) {
            this.orderId = orderId;
            this.customerId = customerId;
            this.status = status;
            this.totalPrice = totalPrice;
            this.timestamp = System.currentTimeMillis();
        }
    }

    @Override
    public OrderResponse processOrder(OrderRequest orderRequest) {
        LOGGER.info("Received order processing request");

        try {
            // Step 1: Validate request is not null
            if (orderRequest == null) {
                return createErrorResponse("VALIDATION_ERROR", "Order request is null");
            }

            // Step 2: Sanitize and validate all input fields
            String validationError = validateAndSanitizeRequest(orderRequest);
            if (validationError != null) {
                LOGGER.warning("Input validation failed: " + validationError);
                return createErrorResponse("VALIDATION_ERROR", validationError);
            }

            // Step 3: Verify HMAC integrity to prevent parameter tampering
            if (!integrityValidator.validateRequestIntegrity(orderRequest)) {
                LOGGER.severe("SOAP parameter tampering detected for customer: " + orderRequest.getCustomerId());
                return createErrorResponse("INTEGRITY_ERROR",
                    "Request integrity validation failed. Parameters may have been tampered with.");
            }

            // Step 4: Validate each item against server-side catalog (CRITICAL anti-tampering)
            String priceValidationError = validatePricesAgainstCatalog(orderRequest.getItems());
            if (priceValidationError != null) {
                LOGGER.severe("Price tampering detected: " + priceValidationError);
                return createErrorResponse("PRICE_TAMPERING",
                    "Price validation failed: " + priceValidationError);
            }

            // Step 5: Validate quantities against catalog limits
            String quantityValidationError = validateQuantitiesAgainstCatalog(orderRequest.getItems());
            if (quantityValidationError != null) {
                LOGGER.warning("Quantity validation failed: " + quantityValidationError);
                return createErrorResponse("QUANTITY_ERROR", quantityValidationError);
            }

            // Step 6: Calculate total using SERVER-SIDE authoritative prices (never trust client prices)
            BigDecimal totalPrice = calculateTotalFromCatalog(orderRequest.getItems());

            // Step 7: Validate total order amount
            if (!InputSanitizer.isValidOrderTotal(totalPrice)) {
                LOGGER.warning("Order total exceeds maximum allowed: " + totalPrice);
                return createErrorResponse("ORDER_LIMIT_ERROR",
                    "Order total exceeds maximum allowed amount");
            }

            // Step 8: Check for duplicate orders (idempotency)
            if (isDuplicateOrder(orderRequest)) {
                LOGGER.warning("Duplicate order detected for customer: " + orderRequest.getCustomerId());
                return createErrorResponse("DUPLICATE_ORDER", "This order appears to be a duplicate");
            }

            // Step 9: Process the order
            String orderId = generateSecureOrderId();
            int itemCount = orderRequest.getItems().size();

            // Store order record
            OrderRecord record = new OrderRecord(orderId, orderRequest.getCustomerId(), "CONFIRMED", totalPrice);
            orderStore.put(orderId, record);

            LOGGER.info("Order processed successfully. OrderId: " + orderId +
                ", Customer: " + orderRequest.getCustomerId() +
                ", Total: " + totalPrice +
                ", Items: " + itemCount);

            return new OrderResponse(
                orderId,
                "CONFIRMED",
                "Order processed successfully. Total calculated using verified catalog prices.",
                totalPrice,
                itemCount
            );

        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Unexpected error processing order", e);
            return createErrorResponse("INTERNAL_ERROR", "An internal error occurred while processing the order");
        }
    }

    @Override
    public OrderStatusResponse getOrderStatus(String orderId) {
        String sanitizedId = InputSanitizer.sanitizeId(orderId);
        if (sanitizedId == null) {
            return new OrderStatusResponse(orderId, "ERROR", "Invalid order ID format");
        }

        OrderRecord record = orderStore.get(sanitizedId);
        if (record == null) {
            return new OrderStatusResponse(sanitizedId, "NOT_FOUND", "Order not found");
        }

        return new OrderStatusResponse(record.orderId, record.status,
            "Order total: " + record.totalPrice.toPlainString());
    }

    private String validateAndSanitizeRequest(OrderRequest request) {
        // Validate customer ID
        String customerId = InputSanitizer.sanitizeId(request.getCustomerId());
        if (customerId == null) {
            return "Invalid or missing customer ID";
        }
        request.setCustomerId(customerId);

        // Validate customer name
        String customerName = InputSanitizer.sanitizeText(request.getCustomerName());
        if (customerName == null) {
            return "Invalid or missing customer name";
        }
        request.setCustomerName(customerName);

        // Validate shipping address
        String address = InputSanitizer.sanitizeText(request.getShippingAddress());
        if (address == null) {
            return "Invalid or missing shipping address";
        }
        request.setShippingAddress(address);

        // Validate items list
        List<OrderItem> items = request.getItems();
        if (items == null || items.isEmpty()) {
            return "Order must contain at least one item";
        }

        if (!InputSanitizer.isValidItemCount(items.size())) {
            return "Number of items exceeds maximum allowed per order";
        }

        // Validate each item
        for (OrderItem item : items) {
            String itemId = InputSanitizer.sanitizeId(item.getItemId());
            if (itemId == null) {
                return "Invalid item ID: " + item.getItemId();
            }
            item.setItemId(itemId);

            String itemName = InputSanitizer.sanitizeText(item.getItemName());
            if (itemName == null) {
                return "Invalid item name for item: " + itemId;
            }
            item.setItemName(itemName);

            if (!InputSanitizer.isValidQuantity(item.getQuantity())) {
                return "Invalid quantity for item: " + itemId;
            }

            if (!InputSanitizer.isValidPrice(item.getUnitPrice())) {
                return "Invalid price for item: " + itemId;
            }
        }

        // Validate request hash is present
        if (request.getRequestHash() == null || request.getRequestHash().trim().isEmpty()) {
            return "Request integrity hash is required";
        }

        return null;
    }

    /**
     * CRITICAL: Validate that prices sent by client match server-side catalog prices.
     * This prevents SOAP parameter tampering where an attacker modifies prices in transit.
     */
    private String validatePricesAgainstCatalog(List<OrderItem> items) {
        for (OrderItem item : items) {
            if (!productCatalog.isValidItem(item.getItemId())) {
                return "Unknown item ID: " + item.getItemId();
            }

            BigDecimal catalogPrice = productCatalog.getAuthorizedPrice(item.getItemId());
            // Compare with scale to avoid floating point issues
            if (item.getUnitPrice().setScale(2, RoundingMode.HALF_UP)
                    .compareTo(catalogPrice.setScale(2, RoundingMode.HALF_UP)) != 0) {
                LOGGER.severe("PRICE TAMPERING DETECTED - Item: " + item.getItemId() +
                    ", Submitted price: " + item.getUnitPrice() +
                    ", Catalog price: " + catalogPrice);
                return "Price mismatch for item " + item.getItemId() +
                    ". Submitted: " + item.getUnitPrice() + ", Expected: " + catalogPrice;
            }
        }
        return null;
    }

    private String validateQuantitiesAgainstCatalog(List<OrderItem> items) {
        for (OrderItem item : items) {
            int maxQty = productCatalog.getMaxQuantity(item.getItemId());
            if (item.getQuantity() > maxQty) {
                return "Quantity " + item.getQuantity() + " exceeds maximum " + maxQty +
                    " for item " + item.getItemId();
            }
        }
        return null;
    }

    /**
     * Calculate total using SERVER-SIDE catalog prices only.
     * Never use client-submitted prices for calculation.
     */
    private BigDecimal calculateTotalFromCatalog(List<OrderItem> items) {
        BigDecimal total = BigDecimal.ZERO;
        for (OrderItem item : items) {
            // Always use the catalog price, not the submitted price
            BigDecimal catalogPrice = productCatalog.getAuthorizedPrice(item.getItemId());
            BigDecimal itemTotal = catalogPrice.multiply(new BigDecimal(item.getQuantity()));
            total = total.add(itemTotal);
        }
        return total.setScale(2, RoundingMode.HALF_UP);
    }

    private boolean isDuplicateOrder(OrderRequest request) {
        // Simple duplicate detection based on recent orders from same customer
        long now = System.currentTimeMillis();
        long fiveMinutesAgo = now - (5 * 60 * 1000);

        return orderStore.values().stream()
            .anyMatch(record ->
                record.customerId.equals(request.getCustomerId()) &&
                record.timestamp > fiveMinutesAgo &&
                record.totalPrice.compareTo(calculateTotalFromCatalog(request.getItems())) == 0
            );
    }

    private String generateSecureOrderId() {
        return "ORD-" + UUID.randomUUID().toString().replace("-", "").substring(0, 16).toUpperCase();
    }

    private OrderResponse createErrorResponse(String errorCode, String message) {
        return new OrderResponse(
            "N/A",
            "REJECTED",
            "[" + errorCode + "] " + message,
            BigDecimal.ZERO,
            0
        );
    }
}

