// OrderServicePublisher.java - Standalone publisher for testing
package com.b2b.orderservice;

import javax.xml.ws.Endpoint;
import java.util.logging.Logger;

public class OrderServicePublisher {

    private static final Logger LOGGER = Logger.getLogger(OrderServicePublisher.class.getName());

    public static void main(String[] args) {
        String url = "http://localhost:8080/b2b/orderservice";
        OrderServiceImpl implementor = new OrderServiceImpl();
        Endpoint endpoint = Endpoint.publish(url, implementor);

        LOGGER.info("B2B Order Service published at: " + url);
        LOGGER.info("WSDL available at: " + url + "?wsdl");
        LOGGER.info("Press Ctrl+C to stop the service");

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            LOGGER.info("Shutting down Order Service...");
            endpoint.stop();
        }));
    }
}

// OrderServiceClient.java - Example B2B client demonstrating proper request signing
package com.b2b.orderservice;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.List;

public class OrderServiceClient {

    public static void main(String[] args) {
        // Demonstrate how a B2B partner should construct a signed request
        System.out.println("=== B2B Order Service Client Demo ===\n");

        // Build order request
        OrderRequest request = new OrderRequest();
        request.setCustomerId("CUST-001");
        request.setCustomerName("Acme Corporation");
        request.setShippingAddress("123 Business Ave, Suite 100, Commerce City, CA 90210");

        List<OrderItem> items = new ArrayList<>();
        items.add(new OrderItem("ITEM-001", "Widget A", 10, new BigDecimal("29.99")));
        items.add(new OrderItem("ITEM-003", "Gadget Pro", 5, new BigDecimal("99.99")));
        request.setItems(items);

        // Sign the request with shared secret (prevents tampering in transit)
        IntegrityValidator validator = IntegrityValidator.getInstance();
        String secret = validator.getCustomerSecret("CUST-001");
        String hash = validator.computeHash(request, secret);
        request.setRequestHash(hash);

        System.out.println("Order Request Details:");
        System.out.println("  Customer: " + request.getCustomerId() + " - " + request.getCustomerName());
        System.out.println("  Address: " + request.getShippingAddress());
        System.out.println("  Items:");
        for (OrderItem item : items) {
            System.out.println("    " + item.getItemId() + " - " + item.getItemName() +
                " x" + item.getQuantity() + " @ $" + item.getUnitPrice());
        }
        System.out.println("  Request Hash: " + hash);

        // Verify integrity
        boolean isValid = validator.validateRequestIntegrity(request);
        System.out.println("\n  Integrity Check: " + (isValid ? "PASSED" : "FAILED"));

        // Demonstrate tampering detection
        System.out.println("\n=== Tampering Detection Demo ===\n");
        OrderRequest tamperedRequest = new OrderRequest();
        tamperedRequest.setCustomerId("CUST-001");
        tamperedRequest.setCustomerName("Acme Corporation");
        tamperedRequest.setShippingAddress("123 Business Ave, Suite 100, Commerce City, CA 90210");

        List<OrderItem> tamperedItems = new ArrayList<>();
        // Attacker changes price from 29.99 to 0.01
        tamperedItems.add(new OrderItem("ITEM-001", "Widget A", 10, new BigDecimal("0.01")));
        tamperedItems.add(new OrderItem("ITEM-003", "Gadget Pro", 5, new BigDecimal("99.99")));
        tamperedRequest.setItems(tamperedItems);
        // Attacker reuses the original hash
        tamperedRequest.setRequestHash(hash);

        boolean isTamperedValid = validator.validateRequestIntegrity(tamperedRequest);
        System.out.println("Tampered request (price changed 29.99 -> 0.01):");
        System.out.println("  Integrity Check: " + (isTamperedValid ? "PASSED (BUG!)" : "FAILED - Tampering Detected!"));

        // Demonstrate quantity tampering
        OrderRequest qtyTamperedRequest = new OrderRequest();
        qtyTamperedRequest.setCustomerId("CUST-001");
        qtyTamperedRequest.setCustomerName("Acme Corporation");
        qtyTamperedRequest.setShippingAddress("123 Business Ave, Suite 100, Commerce City, CA 90210");

        List<OrderItem> qtyTamperedItems = new ArrayList<>();
        // Attacker changes quantity from 10 to 10000
        qtyTamperedItems.add(new OrderItem("ITEM-001", "Widget A", 10000, new BigDecimal("29.99")));
        qtyTamperedItems.add(new OrderItem("ITEM-003", "Gadget Pro", 5, new BigDecimal("99.99")));
        qtyTamperedRequest.setItems(qtyTamperedItems);
        qtyTamperedRequest.setRequestHash(hash);

        boolean isQtyTamperedValid = validator.validateRequestIntegrity(qtyTamperedRequest);
        System.out.println("\nTampered request (quantity changed 10 -> 10000):");
        System.out.println("  Integrity Check: " + (isQtyTamperedValid ? "PASSED (BUG!)" : "FAILED - Tampering Detected!"));
    }
}